+		test("GET /api/tasks returns empty tasks when JSON lacks a tasks key", async () => {
+			const dataDir = mkdtempSync(join(tmpdir(), "sprout-tasks-notasks-"));
+			const logsDir = join(dataDir, "logs", "tasks-notasks-session");
